const fs = require('fs');
const data = $input.first().json;
const logPath = '/workspace/07_Operaciones/FG_Operations_Log.md';

const timestamp = data.timestamp || new Date().toISOString();
const date = timestamp.split('T')[0];
const time = timestamp.split('T')[1]?.substring(0, 5) || '00:00';
const evento = data.evento || 'EVENTO';
const pieza = data.pieza || '—';
const detalles = data.detalles || '';

const logLine = `| ${date} | ${time} | ${evento} | ${pieza} | ${detalles} |`;

let content = '';
try {
  content = fs.readFileSync(logPath, 'utf8');
} catch (e) {
  content = '# FG Operations Log\n\n| Fecha | Hora | Evento | Pieza | Detalles |\n|-------|------|--------|-------|----------|\n';
}

content += logLine + '\n';
fs.writeFileSync(logPath, content, 'utf8');

return [{ json: { logged: true, logLine } }];
